Sure! Let's create a reusable `DataTable` component in TypeScript React with the specified features.

### Step 1: Define Types

First, let's define some types to make our component generic and type-safe.

```typescript
import React from 'react';

// Define the shape of a column
export interface Column<T> {
    key: keyof T;
    label?: string;
    sortable?: boolean;
}

// Define the props for the DataTable component
interface DataTableProps<T> {
    data: T[];
    columns: Column<T>[];
    pageSize?: number;
}
```

### Step 2: Create the DataTable Component

Next, let's create the `DataTable` component itself.

```typescript
import React, { useState } from 'react';

const DataTable = <T extends object>({ data, columns, pageSize = 10 }: DataTableProps<T>) => {
    const [sortConfig, setSortConfig] = useState<{ key: keyof T; direction: 'ascending' | 'descending' }>({
        key: Object.keys(data[0])[0] as keyof T,
        direction: 'ascending',
    });
    const [currentPage, setCurrentPage] = useState(1);
    const [searchTerm, setSearchTerm] = useState('');

    // Function to handle sorting
    const sortedData = React.useMemo(() => {
        if (!Array.isArray(data) || data.length === 0) return [];

        let sortableData = [...data];
        if (sortConfig !== null) {
            sortableData.sort((a, b) => {
                if (a[sortConfig.key] < b[sortConfig.key]) {
                    return sortConfig.direction === 'ascending' ? -1 : 1;
                }
                if (a[sortConfig.key] > b[sortConfig.key]) {
                    return sortConfig.direction === 'ascending' ? 1 : -1;
                }
                return 0;
            });
        }

        // Filter data based on search term
        const filteredData = sortableData.filter((item) =>
            columns.some((column) => 
                item[column.key]
                    ?.toString()
                    .toLowerCase()
                    .includes(searchTerm.toLowerCase())
            )
        );

        return filteredData;
    }, [data, sortConfig, columns, searchTerm]);

    // Pagination logic
    const totalPages = Math.ceil(sortedData.length / pageSize);
    const currentData = sortedData.slice((currentPage - 1) * pageSize, currentPage * pageSize);

    const requestSort = (key: keyof T) => {
        let direction: 'ascending' | 'descending' = 'ascending';
        if (sortConfig.key === key && sortConfig.direction === 'ascending') {
            direction = 'descending';
        }
        setSortConfig({ key, direction });
    };

    // Function to handle search input
    const handleSearchChange = (event: React.ChangeEvent<HTMLInputElement>) => {
        setSearchTerm(event.target.value);
    };

    return (
        <div>
            <input type="text" placeholder="Search..." value={searchTerm} onChange={handleSearchChange} />
            {sortedData.length === 0 ? (
                <p>No data found</p>
            ) : (
                <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                    <thead>
                        <tr>
                            {columns.map((column) => (
                                <th
                                    key={String(column.key)}
                                    onClick={() =>
                                        column.sortable !== false && requestSort(column.key)
                                    }
                                    style={{
                                        cursor: column.sortable !== false ? 'pointer' : 'default',
                                        borderBottom: '2px solid black',
                                        padding: '8px 16px',
                                    }}
                                >
                                    {column.label || String(column.key)}
                                    {sortConfig.key === column.key ? (
                                        sortConfig.direction === 'ascending' ? ' 🔼' : ' 🔽'
                                    ) : null}
                                </th>
                            ))}
                        </tr>
                    </thead>
                    <tbody>
                        {currentData.map((item, index) => (
                            <tr key={index}>
                                {columns.map((column) => (
                                    <td
                                        key={String(column.key)}
                                        style={{ padding: '8px 16px', borderBottom: '1px solid #ddd' }}
                                    >
                                        {item[column.key]}
                                    </td>
                                ))}
                            </tr>
                        ))}
                    </tbody>
                </table>
            )}
            <div>
                <button onClick={() => setCurrentPage((prev) => Math.max(prev - 1, 1))} disabled={currentPage === 1}>
                    Previous
                </button>
                <span> Page {currentPage} of {totalPages}</span>
                <button onClick={() => setCurrentPage((prev) => Math.min(prev + 1, totalPages))} disabled={currentPage === totalPages}>
                    Next
                </button>
            </div>
        </div>
    );
};

export default DataTable;
```

### Step 3: Usage Example with Sample Data

Now let's use the `DataTable` component with some sample data.

```typescript
import React from 'react';
import ReactDOM from 'react-dom';

// Define a type for your sample data
interface User {
    id: number;
    name: string;
    email: string;
    age: number;
}

const users: User[] = [
    { id: 1, name: 'John Doe', email: 'john@example.com', age: 28 },
    { id: 2, name: 'Jane Smith', email: 'jane@example.com', age: 34 },
    { id: 3, name: 'Sam Green', email: 'sam@example.com', age: 23 },
];

const App = () => {
    const columns: Column<User>[] = [
        { key: 'id', label: 'ID', sortable: true },
        { key: 'name', label: 'Name', sortable: true },
        { key: 'email', label: 'Email' },
        { key: 'age', label: 'Age', sortable: true },
    ];

    return (
        <div>
            <h1>User List</h1>
            <DataTable<User> data={users} columns={columns} pageSize={2} />
        </div>
    );
};

ReactDOM.render(<App />, document.getElementById('root'));
```

### Explanation

- **Generic Types**: The `DataTable` component is generic over the type of its data (`T`). This allows it to handle any type of object array.
- **Sorting**: Clicking on a column header toggles sorting between ascending and descending order.
- **Pagination**: Data is paginated based on the provided `pageSize`. Navigation buttons allow users to move through pages.
- **Search/Filter**: A search input filters data across all columns.
- **Loading and Empty States**: While this example doesn't include asynchronous loading, you can add a loading state by adding additional props and conditional rendering. The component also handles empty states by displaying "No data found" when no results match the search criteria.

