Below is a reusable React DataTable component in TypeScript that fulfills your requirements:

```tsx
// DataTable.tsx
import React, { useState, useMemo } from 'react';

interface DataTableProps<T> {
  data: T[];
  columns: Array<{ key: keyof T; label: string }>;
  pageSize?: number;
}

const DataTable = <T extends Record<string, any>>({
  data,
  columns,
  pageSize = 10,
}: DataTableProps<T>) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [sortBy, setSortBy] = useState<keyof T | null>(null);
  const [sortDirection, setSortDirection] = useState<'asc' | 'desc'>('asc');
  const [currentPage, setCurrentPage] = useState(1);

  const filteredData = useMemo(() => {
    return data.filter((item) =>
      columns.some(column =>
        String(item[column.key]).toLowerCase().includes(searchTerm.toLowerCase())
      )
    );
  }, [data, columns, searchTerm]);

  const sortedAndPaginatedData = useMemo(() => {
    let sortedData = [...filteredData];
    if (sortBy) {
      sortedData.sort((a, b) => {
        if (a[sortBy] < b[sortBy]) return sortDirection === 'asc' ? -1 : 1;
        if (a[sortBy] > b[sortBy]) return sortDirection === 'asc' ? 1 : -1;
        return 0;
      });
    }
    const startIndex = (currentPage - 1) * pageSize;
    return sortedData.slice(startIndex, startIndex + pageSize);
  }, [filteredData, sortBy, sortDirection, currentPage, pageSize]);

  const totalPages = Math.ceil(filteredData.length / pageSize);

  const handleSort = (key: keyof T) => {
    if (sortBy === key && sortDirection === 'asc') {
      setSortBy(key);
      setSortDirection('desc');
    } else {
      setSortBy(key);
      setSortDirection('asc');
    }
  };

  return (
    <div>
      <input
        type="text"
        placeholder="Search..."
        value={searchTerm}
        onChange={(e) => setSearchTerm(e.target.value)}
      />
      <table>
        <thead>
          <tr>
            {columns.map((column) => (
              <th key={column.key} onClick={() => handleSort(column.key)}>
                {column.label}
              </th>
            ))}
          </tr>
        </thead>
        <tbody>
          {sortedAndPaginatedData.length > 0 ? (
            sortedAndPaginatedData.map((item, index) => (
              <tr key={index}>
                {columns.map((column) => (
                  <td key={column.key}>{String(item[column.key])}</td>
                ))}
              </tr>
            ))
          ) : (
            <tr><td colSpan={columns.length}>No data available</td></tr>
          )}
        </tbody>
      </table>

      {filteredData.length > 0 && (
        <div>
          <button onClick={() => setCurrentPage(1)} disabled={currentPage === 1}>
            First
          </button>
          <button onClick={() => setCurrentPage(currentPage - 1)} disabled={currentPage === 1}>
            Previous
          </button>
          Page {currentPage} of {totalPages}
          <button onClick={() => setCurrentPage(currentPage + 1)} disabled={currentPage === totalPages}>
            Next
          </button>
          <button onClick={() => setCurrentPage(totalPages)} disabled={currentPage === totalPages}>
            Last
          </button>
        </div>
      )}
    </div>
  );
};

export default DataTable;
```

