### 1. The DataTable Component

```tsx
import React, { useState, useMemo } from 'react';

// --- Types ---

export interface Column<T> {
  key: keyof T;
  label: string;
  sortable?: boolean;
  // Custom render function for complex cells (e.g., buttons, badges)
  render?: (value: any, item: T) => React.ReactNode;
}

export type SortDirection = 'asc' | 'desc' | null;

interface SortConfig {
  key: string;
  direction: SortDirection;
}

interface DataTableProps<T> {
  data: T[];
  columns: Column<T>[];
  loading?: boolean;
  pageSize?: number;
  searchPlaceholder?: string;
}

// --- Component ---

export function DataTable<T extends { id: string | number }>({
  data,
  columns,
  loading = false,
  pageSize = 10,
  searchPlaceholder = "Search...",
}: DataTableProps<T>) {
  // State
  const [searchQuery, setSearchQuery] = useState('');
  const [sortConfig, setSortConfig] = useState<SortConfig>({ key: '', direction: null });
  const [currentPage, setCurrentPage] = useState(1);

  // 1. Filter Logic
  const filteredData = useMemo(() => {
    if (!searchQuery) return data;

    return data.filter((item) => 
      Object.values(item).some((val) => 
        String(val).toLowerCase().includes(searchQuery.toLowerCase())
      )
    );
  }, [data, searchQuery]);

  // 2. Sort Logic
  const sortedData = useMemo(() => {
    const sortableItems = [...filteredData];
    if (sortConfig.direction === null) return sortableItems;

    sortableItems.sort((a, b) => {
      const aValue = a[sortConfig.key as keyof T];
      const bValue = b[sortConfig.key as keyof T];

      if (aValue < bValue) return sortConfig.direction === 'asc' ? -1 : 1;
      if (aValue > bValue) return sortConfig.direction === 'asc' ? 1 : -1;
      return 0;
    });
    return sortableItems;
  }, [filteredData, sortConfig]);

  // 3. Pagination Logic
  const paginatedData = useMemo(() => {
    const startIndex = (currentPage - 1) * pageSize;
    return sortedData.slice(startIndex, startIndex + pageSize);
  }, [sortedData, currentPage, pageSize]);

  const totalPages = Math.ceil(sortedData.length / pageSize);

  // Handlers
  const requestSort = (key: string) => {
    let direction: SortDirection = 'asc';
    if (sortConfig.key === key && sortConfig.direction === 'asc') {
      direction = 'desc';
    } else if (sortConfig.key === key && sortConfig.direction === 'desc') {
      direction = null;
    }
    setSortConfig({ key, direction });
  };

  return (
    <div className="table-container">
      {/* Toolbar */}
      <div className="table-toolbar">
        <input
          type="text"
          placeholder={searchPlaceholder}
          value={searchQuery}
          onChange={(e) => {
            setSearchQuery(e.target.value);
            setCurrentPage(1); // Reset to page 1 on search
          }}
          className="search-input"
        />
      </div>

      {/* Table */}
      <div className="table-wrapper">
        <table className="data-table">
          <thead>
            <tr>
              {columns.map((col) => (
                <th 
                  key={String(col.key)} 
                  onClick={() => col.sortable && requestSort(String(col.key))}
                  className={`${col.sortable ? 'sortable' : ''} ${sortConfig.key === col.key ? 'active-sort' : ''}`}
                >
                  {col.label}
                  {col.sortable && (
                    <span className="sort-indicator">
                      {sortConfig.key === col.key 
                        ? (sortConfig.direction === 'asc' ? ' 🔼' : sortConfig.direction === 'desc' ? ' 🔽' : ' ↕️') 
                        : ' ↕️'}
                    </span>
                  )}
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {loading ? (
              <tr><td colSpan={columns.length} className="center-cell">Loading data...</td></tr>
            ) : paginatedData.length === 0 ? (
              <tr><td colSpan={columns.length} className="center-cell">No records found.</td></tr>
            ) : (
              paginatedData.map((item) => (
                <tr key={item.id}>
                  {columns.map((col) => (
                    <td key={String(col.key)}>
                      {col.render 
                        ? col.render(item[col.key], item) 
                        : (item[col.key] as React.ReactNode)}
                    </td>
                  ))}
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>

      {/* Pagination */}
      {!loading && sortedData.length > 0 && (
        <div className="pagination">
          <button 
            disabled={currentPage === 1} 
            onClick={() => setCurrentPage(p => p - 1)}
          >
            Previous
          </button>
          <span>Page {currentPage} of {totalPages}</span>
          <button 
            disabled={currentPage === totalPages} 
            onClick={() => setCurrentPage(p => p + 1)}
          >
            Next
          </button>
        </div>
      )}
    </div>
  );
}
```

