## 2. Custom Hooks

```typescript
// hooks/useDataTableSort.ts

import { useState, useMemo } from 'react';
import { SortConfig, SortDirection } from '../types/dataTable';

export function useDataTableSort<T>(data: T[], initialSortKey?: keyof T) {
  const [sortConfig, setSortConfig] = useState<SortConfig<T>>({
    key: initialSortKey || ('id' as keyof T),
    direction: null,
  });

  const toggleSort = (key: keyof T) => {
    setSortConfig((prev) => {
      if (prev.key === key) {
        const directions: (SortDirection | SortDirection)[] = [null, 'asc', 'desc'];
        const currentIndex = directions.indexOf(prev.direction);
        const nextDirection = directions[(currentIndex + 1) % directions.length] as SortDirection;
        return { key, direction: nextDirection };
      }
      return { key, direction: 'asc' };
    });
  };

  const sortedData = useMemo(() => {
    if (!sortConfig.direction) return data;

    const sorted = [...data].sort((a, b) => {
      const aValue = a[sortConfig.key];
      const bValue = b[sortConfig.key];

      if (aValue === bValue) return 0;
      if (aValue === null || aValue === undefined) return 1;
      if (bValue === null || bValue === undefined) return -1;

      const comparison = aValue < bValue ? -1 : 1;
      return sortConfig.direction === 'asc' ? comparison : -comparison;
    });

    return sorted;
  }, [data, sortConfig]);

  return { sortedData, sortConfig, toggleSort };
}
```

```typescript
// hooks/useDataTablePagination.ts

import { useState, useMemo } from 'react';

export function useDataTablePagination<T>(data: T[], pageSize: number) {
  const [currentPage, setCurrentPage] = useState(1);

  const paginationData = useMemo(() => {
    const totalPages = Math.ceil(data.length / pageSize);
    const startIndex = (currentPage - 1) * pageSize;
    const endIndex = startIndex + pageSize;
    const pageData = data.slice(startIndex, endIndex);

    return {
      pageData,
      currentPage,
      totalPages,
      totalItems: data.length,
      hasNextPage: currentPage < totalPages,
      hasPrevPage: currentPage > 1,
    };
  }, [data, pageSize, currentPage]);

  const goToPage = (page: number) => {
    const totalPages = Math.ceil(data.length / pageSize);
    if (page >= 1 && page <= totalPages) {
      setCurrentPage(page);
    }
  };

  const goToNextPage = () => goToPage(currentPage + 1);
  const goToPrevPage = () => goToPage(currentPage - 1);
  const resetPage = () => setCurrentPage(1);

  return {
    ...paginationData,
    goToPage,
    goToNextPage,
    goToPrevPage,
    resetPage,
  };
}
