## 2. Validation Layer

```python
# validators.py
from abc import ABC, abstractmethod
from typing import Dict, Any, List
from models import OrderItem

class ValidationError(Exception):
    pass

class Validator(ABC):
    @abstractmethod
    def validate(self, data: Any) -> None:
        pass

class OrderDataValidator(Validator):
    def validate(self, order_data: Dict[str, Any]) -> None:
        self._validate_items(order_data.get('items', []))
        self._validate_email(order_data.get('customer_email'))

    def _validate_items(self, items: List[Dict]) -> None:
        if not items:
            raise ValidationError('No items in order')

        for item in items:
            self._validate_item(item)

    def _validate_item(self, item: Dict[str, Any]) -> None:
        if item.get('quantity', 0) <= 0:
            raise ValidationError(f"Invalid quantity for {item.get('name')}")

        if item.get('price', -1) < 0:
            raise ValidationError(f"Invalid price for {item.get('name')}")

    def _validate_email(self, email: str) -> None:
        if not email:
            raise ValidationError('Customer email is required')
