## 3. Pricing/Tax Strategy

```python
# pricing.py
from abc import ABC, abstractmethod
from typing import Dict, Any

class TaxCalculator(ABC):
    @abstractmethod
    def calculate(self, subtotal: float) -> float:
        pass

class ProvincialTaxCalculator(TaxCalculator):
    TAX_RATES = {
        'ON': 0.13,
        'QC': 0.10,
        'BC': 0.12,
    }
    DEFAULT_RATE = 0.05

    def calculate(self, subtotal: float, province: str = None) -> float:
        rate = self.TAX_RATES.get(province, self.DEFAULT_RATE)
        return round(subtotal * rate, 2)

class ShippingCalculator:
    FREE_SHIPPING_THRESHOLD = 50.00
    STANDARD_SHIPPING = 9.99

    def calculate(self, subtotal: float) -> float:
        return 0.0 if subtotal > self.FREE_SHIPPING_THRESHOLD else self.STANDARD_SHIPPING

class PricingEngine:
    def __init__(self, tax_calculator: TaxCalculator, shipping_calculator: ShippingCalculator):
        self.tax_calculator = tax_calculator
        self.shipping_calculator = shipping_calculator

    def calculate_totals(self, items: list, province: str = None) -> Dict[str, float]:
        subtotal = sum(item['price'] * item['quantity'] for item in items)
        tax = self.tax_calculator.calculate(subtotal, province)
        shipping = self.shipping_calculator.calculate(subtotal)

        return {
            'subtotal': round(subtotal, 2),
            'tax': tax,
            'shipping': shipping,
            'total': round(subtotal + tax + shipping, 2)
        }
```

## 4. Discount Strategy Pattern

```python
# discounts.py
from abc import ABC, abstractmethod
from typing import Optional

class DiscountStrategy(ABC):
    @abstractmethod
    def apply(self, total: float) -> float:
        pass

class PercentageDiscount(DiscountStrategy):
    def __init__(self, percentage: float):
        self.percentage = percentage

    def apply(self, total: float) -> float:
        return round(total * (1 - self.percentage), 2)

class FixedDiscount(DiscountStrategy):
    def __init__(self, amount: float):
        self.amount = amount

    def apply(self, total: float) -> float:
        return round(max(0, total - self.amount), 2)

class CouponRegistry:
    def __init__(self):
        self._coupons = {}

    def register(self, code: str, discount: DiscountStrategy) -> None:
        self._coupons[code] = discount

    def get(self, code: str) -> Optional[DiscountStrategy]:
        return self._coupons.get(code)

class DiscountEngine:
    def __init__(self, coupon_registry: CouponRegistry):
        self.registry = coupon_registry

    def apply_discount(self, total: float, coupon_code: Optional[str] = None) -> float:
        if not coupon_code:
            return total

        discount = self.registry.get(coupon_code)
        if not discount:
            return total

        return discount.apply(total)
```

## 5. Notification Layer

```python
# notifications.py
from abc import ABC, abstractmethod
from typing import Dict, Any
import logging

logger = logging.getLogger(__name__)

class NotificationService(ABC):
    @abstractmethod
    def send(self, recipient: str, order: Dict[str, Any]) -> bool:
        pass

class EmailNotificationService(NotificationService):
    def __init__(self, smtp_config: Dict[str, str]):
        self.smtp_config = smtp_config

    def send(self, recipient: str, order: Dict[str, Any]) -> bool:
        try:
            import smtplib
            from email.mime.text import MIMEText

            message = self._build_message(recipient, order)
            self._send_email(message)
            return True
        except Exception as e:
            logger.error(f"Failed to send email to {recipient}: {str(e)}")
            return False

    def _build_message(self, recipient: str, order: Dict[str, Any]) -> 'MIMEText':
        from email.mime.text import MIMEText

        body = f"""
        Thank you for your order!

        Order ID: {order['id']}
        Total: ${order['total']}
        Status: {order['status']}
        """

        msg = MIMEText(body)
        msg['Subject'] = 'Order Confirmation'
        msg['From'] = self.smtp_config.get('from_address', 'orders@shop.com')
        msg['To'] = recipient
        return msg

    def _send_email(self, msg: 'MIMEText') -> None:
        import smtplib

        with smtplib.SMTP(self.smtp_config.get('host', 'localhost')) as server:
            server.send_message(msg)

class LogNotificationService(NotificationService):
    """Fallback/test notification service"""
    def send(self, recipient: str, order: Dict[str, Any]) -> bool:
        logger.info(f"Order {order['id']} notification for {recipient}: ${order['total']}")
        return True

class CompositeNotificationService(NotificationService):
    """Send notifications through multiple channels"""
    def __init__(self, services: list[NotificationService]):
        self.services = services

    def send(self, recipient: str, order: Dict[str, Any]) -> bool:
        results = [service.send(recipient, order) for service in self.services]
        return any(results)
