## 6. Order Service (Orchestrator)

```python
# order_service.py
from typing import Dict, Any
from models import Order, OrderItem
from validators import OrderDataValidator, ValidationError
from pricing import PricingEngine, ProvincialTaxCalculator, ShippingCalculator
from discounts import DiscountEngine, CouponRegistry
from notifications import NotificationService

class OrderService:
    def __init__(
        self,
        validator: OrderDataValidator,
        pricing_engine: PricingEngine,
        discount_engine: DiscountEngine,
        notification_service: NotificationService
    ):
        self.validator = validator
        self.pricing_engine = pricing_engine
        self.discount_engine = discount_engine
        self.notification_service = notification_service

    def process(self, order_data: Dict[str, Any]) -> Order:
        # Validate
        self.validator.validate(order_data)

        # Calculate pricing
        pricing = self.pricing_engine.calculate_totals(
            order_data['items'],
            order_data.get('province')
        )

        # Apply discounts
        final_total = self.discount_engine.apply_discount(
            pricing['total'],
            order_data.get('coupon_code')
        )

        # Create order
        order = Order.create(
            items=[OrderItem(**item) for item in order_data['items']]
        )
        order.subtotal = pricing['subtotal']
        order.tax = pricing['tax']
        order.shipping = pricing['shipping']
        order.total = final_total

        # Send notification
        self.notification_service.send(order_data['customer_email'], order.__dict__)

        return order
