```typescript
// Type for a function that extracts a key from an item
type KeyFunction<T, K> = (item: T) => K;

// Type for a comparison function
type CompareFn<T> = (a: T, b: T) => number;

/**
 * Groups array items by a key function
 * @template T - The type of items in the array
 * @template K - The type of the grouping key
 * @param array - The array to group
 * @param keyFn - Function that extracts the key from each item
 * @returns An object with keys mapping to arrays of items
 */
function groupBy<T, K extends string | number | symbol>(
  array: T[],
  keyFn: KeyFunction<T, K>
): Record<K, T[]> {
  return array.reduce<Record<K, T[]>>((groups, item) => {
    const key = keyFn(item);
    if (!groups[key]) {
      groups[key] = [];
    }
    groups[key].push(item);
    return groups;
  }, {} as Record<K, T[]>);
}

/**
 * Sorts array items by a key function
 * @template T - The type of items in the array
 * @template K - The type of the sort key
 * @param array - The array to sort
 * @param keyFn - Function that extracts the sort key from each item
 * @param descending - Whether to sort in descending order (default: false)
 * @returns A new sorted array
 */
function sortBy<T, K extends string | number | Date>(
  array: T[],
  keyFn: KeyFunction<T, K>,
  descending: boolean = false
): T[] {
  return [...array].sort((a, b) => {
    const valA = keyFn(a);
    const valB = keyFn(b);
    const cmp = valA < valB ? -1 : valA > valB ? 1 : 0;
    return descending ? -cmp : cmp;
  });
}

/**
 * Creates a function pipeline
 * @template T - The input/output type through the pipeline
 * @param fns - Functions to pipe together
 * @returns A function that applies all piped functions in sequence
 */
function pipe<T>(...fns: Array<(arg: T) => T>): (input: T) => T {
  return (input: T): T => fns.reduce((acc, fn) => fn(acc), input);
}

// Advanced version with multiple types (if you need more flexibility)
/**
 * Creates a type-safe function pipeline with type transformation
 * @template Args - Tuple of argument types
 * @template ReturnTypes - Tuple of return types for each function
 */
type PipeFunction<In, Out> = (arg: In) => Out;

function pipeAdvanced<T extends readonly unknown[]>(
  ...fns: {
    [K in keyof T]: K extends "0"
      ? PipeFunction<any, T[K]>
      : K extends keyof T
        ? PipeFunction<T[K extends `${infer N extends number}` ? N extends 0 ? 0 : `${infer M extends number}` ? M : 0 : 0], T[K]>
        : never;
  }
): (input: any) => unknown {
  return (input: any) => fns.reduce((acc, fn) => fn(acc), input);
}

// Example usage with types:
interface User {
  id: number;
  name: string;
  age: number;
  department: string;
}

const users: User[] = [
  { id: 1, name: "Alice", age: 30, department: "Engineering" },
  { id: 2, name: "Bob", age: 25, department: "Design" },
  { id: 3, name: "Charlie", age: 35, department: "Engineering" },
];

// groupBy usage - returns Record<string, User[]>
const usersByDept = groupBy(users, (user) => user.department);

// sortBy usage - returns User[]
const sortedByAge = sortBy(users, (user) => user.age);
const sortedByAgeDesc = sortBy(users, (user) => user.age, true);

// pipe usage - returns User[]
const processUsers = pipe(
  (users: User[]) => sortBy(users, (u) => u.age),
  (users: User[]) => users.filter((u) => u.age > 25)
);
const result = processUsers(users);
```

**Key improvements:**

1. **Generic Types**: `<T, K>` properly constrain the types
2. **Type Constraints**: `K extends string | number | symbol` for valid object keys
3. **Record Type**: Using `Record<K, T[]>` for the groupBy return type
4. **Function Types**: `KeyFunction<T, K>` for reusability
5. **JSDoc Comments**: Explaining parameters and return types
6. **Proper Array Spread**: Typed arrays maintain type safety
7. **Comparable Types**: Constraints on sortBy's key type (`string | number | Date`)
8. **Example Usage**: Shows how types are properly inferred

