## Hooks

```typescript
// hooks/useDataTable.ts
import { useState, useMemo, useCallback } from 'react';
import type { SortState, ColumnDef } from '../types/datatable.types';

interface UseDataTableOptions<T> {
  data: T[];
  columns: ColumnDef<T>[];
  initialPageSize: number;
}

export function useDataTable<T extends Record<string, unknown>>({
  data,
  columns,
  initialPageSize,
}: UseDataTableOptions<T>) {
  const [searchQuery, setSearchQuery] = useState('');
  const [sortState, setSortState] = useState<SortState<T>>({
    key: null,
    direction: null,
  });
  const [currentPage, setCurrentPage] = useState(1);
  const [pageSize, setPageSize] = useState(initialPageSize);

  // ── Filter ────────────────────────────────────────────────────────────────
  const filteredData = useMemo(() => {
    if (!searchQuery.trim()) return data;

    const query = searchQuery.toLowerCase();
    return data.filter((row) =>
      columns.some(({ key }) => {
        const value = row[key];
        return String(value ?? '').toLowerCase().includes(query);
      }),
    );
  }, [data, searchQuery, columns]);

  // ── Sort ──────────────────────────────────────────────────────────────────
  const sortedData = useMemo(() => {
    if (!sortState.key || !sortState.direction) return filteredData;

    return [...filteredData].sort((a, b) => {
      const aVal = a[sortState.key!];
      const bVal = b[sortState.key!];

      if (aVal === bVal) return 0;

      const isAsc = sortState.direction === 'asc';
      if (aVal === null || aVal === undefined) return isAsc ? -1 : 1;
      if (bVal === null || bVal === undefined) return isAsc ? 1 : -1;

      if (typeof aVal === 'number' && typeof bVal === 'number') {
        return isAsc ? aVal - bVal : bVal - aVal;
      }

      const comparison = String(aVal).localeCompare(String(bVal));
      return isAsc ? comparison : -comparison;
    });
  }, [filteredData, sortState]);

  // ── Paginate ──────────────────────────────────────────────────────────────
  const totalItems = sortedData.length;
  const totalPages = Math.max(1, Math.ceil(totalItems / pageSize));
  const safePage = Math.min(currentPage, totalPages);

  const paginatedData = useMemo(() => {
    const start = (safePage - 1) * pageSize;
    return sortedData.slice(start, start + pageSize);
  }, [sortedData, safePage, pageSize]);

  // ── Handlers ──────────────────────────────────────────────────────────────
  const handleSort = useCallback((key: keyof T) => {
    setSortState((prev) => ({
      key,
      direction:
        prev.key === key
          ? prev.direction === 'asc'
            ? 'desc'
            : prev.direction === 'desc'
              ? null
              : 'asc'
          : 'asc',
    }));
    setCurrentPage(1);
  }, []);

  const handleSearch = useCallback((query: string) => {
    setSearchQuery(query);
    setCurrentPage(1);
  }, []);

  const handlePageSizeChange = useCallback((size: number) => {
    setPageSize(size);
    setCurrentPage(1);
  }, []);

  return {
    paginatedData,
    searchQuery,
    sortState,
    currentPage: safePage,
    pageSize,
    totalItems,
    totalPages,
    handleSort,
    handleSearch,
    handlePageSizeChange,
    setCurrentPage,
  };
}
```

