```python
from dataclasses import dataclass
from typing import Protocol, Any

from .models import OrderItem


@dataclass(frozen=True)
class ValidationResult:
    is_valid: bool
    error: str = ""

    @classmethod
    def ok(cls) -> "ValidationResult":
        return cls(is_valid=True)

    @classmethod
    def fail(cls, error: str) -> "ValidationResult":
        return cls(is_valid=False, error=error)


class OrderValidator(Protocol):
    """Open for extension: add new validators without modifying existing ones."""
    def validate(self, order_data: dict[str, Any]) -> ValidationResult:
        ...


class ItemsPresenceValidator:
    def validate(self, order_data: dict[str, Any]) -> ValidationResult:
        if not order_data.get("items"):
            return ValidationResult.fail("No items provided")
        return ValidationResult.ok()


class CustomerEmailValidator:
    def validate(self, order_data: dict[str, Any]) -> ValidationResult:
        if not order_data.get("customer_email"):
            return ValidationResult.fail("No customer email provided")
        return ValidationResult.ok()


class ItemQuantityValidator:
    def validate(self, order_data: dict[str, Any]) -> ValidationResult:
        for item in order_data.get("items", []):
            if item["quantity"] <= 0:
                return ValidationResult.fail(
                    f"Invalid quantity for '{item['name']}': must be > 0"
                )
        return ValidationResult.ok()


class ItemPriceValidator:
    def validate(self, order_data: dict[str, Any]) -> ValidationResult:
        for item in order_data.get("items", []):
            if item["price"] < 0:
                return ValidationResult.fail(
                    f"Invalid price for '{item['name']}': must be >= 0"
                )
        return ValidationResult.ok()


class CompositeOrderValidator:
    """Runs all validators in sequence. Fails fast on first error."""

    def __init__(self, validators: list[OrderValidator]) -> None:
        self._validators = validators

    def validate(self, order_data: dict[str, Any]) -> ValidationResult:
        for validator in self._validators:
            result = validator.validate(order_data)
            if not result.is_valid:
                return result
        return ValidationResult.ok()


def build_default_validator() -> CompositeOrderValidator:
    """Factory: wire up the standard validation pipeline."""
    return CompositeOrderValidator([
        ItemsPresenceValidator(),
        CustomerEmailValidator(),
        ItemQuantityValidator(),
        ItemPriceValidator(),
    ])
