## `pricing.py` — Pricing Calculations (SRP)

```python
from dataclasses import dataclass
from typing import Any

from .models import OrderItem, PricingBreakdown


@dataclass(frozen=True)
class TaxPolicy:
    province_rates: dict[str, float]
    default_rate: float

    def rate_for(self, province: str | None) -> float:
        return self.province_rates.get(province or "", self.default_rate)


@dataclass(frozen=True)
class ShippingPolicy:
    free_threshold: float
    flat_rate: float

    def cost_for(self, subtotal: float) -> float:
        return 0.0 if subtotal >= self.free_threshold else self.flat_rate


class PricingCalculator:
    def __init__(self, tax_policy: TaxPolicy, shipping_policy: ShippingPolicy) -> None:
        self._tax_policy = tax_policy
        self._shipping_policy = shipping_policy

    def calculate(
        self,
        items: list[OrderItem],
        province: str | None,
        discount: float = 0.0,
    ) -> PricingBreakdown:
        subtotal = sum(item.price * item.quantity for item in items)
        tax_rate = self._tax_policy.rate_for(province)
        tax = round(subtotal * tax_rate, 2)
        shipping = self._shipping_policy.cost_for(subtotal)
        pre_discount_total = subtotal + tax + shipping
        total = round(pre_discount_total - discount, 2)

        return PricingBreakdown(
            subtotal=round(subtotal, 2),
            tax=tax,
            tax_rate=tax_rate,
            shipping=shipping,
            discount=round(discount, 2),
            total=total,
        )


def build_default_pricing_calculator() -> PricingCalculator:
    tax_policy = TaxPolicy(
        province_rates={"ON": 0.13},
        default_rate=0.05,
    )
    shipping_policy = ShippingPolicy(free_threshold=50.0, flat_rate=9.99)
    return PricingCalculator(tax_policy, shipping_policy)
