## `discounts.py` — Discount Resolution (OCP + LSP)

```python
from typing import Protocol

from .models import OrderItem


class DiscountStrategy(Protocol):
    """New coupon types extend this contract without touching existing code."""
    def apply(self, pre_discount_total: float) -> float:
        """Returns the discount AMOUNT (not the new total)."""
        ...


class PercentageDiscount:
    def __init__(self, rate: float) -> None:
        if not 0 < rate < 1:
            raise ValueError(f"Rate must be between 0 and 1, got {rate}")
        self._rate = rate

    def apply(self, pre_discount_total: float) -> float:
        return round(pre_discount_total * self._rate, 2)


class FlatDiscount:
    def __init__(self, amount: float) -> None:
        if amount <= 0:
            raise ValueError(f"Flat discount must be > 0, got {amount}")
        self._amount = amount

    def apply(self, pre_discount_total: float) -> float:
        return min(self._amount, pre_discount_total)  # Can't discount below $0


class NoDiscount:
    def apply(self, pre_discount_total: float) -> float:
        return 0.0


class CouponRegistry:
    def __init__(self, coupons: dict[str, DiscountStrategy]) -> None:
        self._coupons = coupons

    def resolve(self, coupon_code: str | None) -> DiscountStrategy:
        if not coupon_code:
            return NoDiscount()
        return self._coupons.get(coupon_code, NoDiscount())


def build_default_coupon_registry() -> CouponRegistry:
    return CouponRegistry({
        "SAVE10": PercentageDiscount(0.10),
        "SAVE20": PercentageDiscount(0.20),
        "FLAT5":  FlatDiscount(5.0),
    })
