## `notifications.py` — Notification Delivery (DIP + ISP)

```python
import logging
import smtplib
from email.mime.text import MIMEText
from typing import Protocol

from .models import Order

logger = logging.getLogger(__name__)


class OrderNotifier(Protocol):
    """Depend on this abstraction, not on smtplib directly."""
    def notify_order_confirmed(self, order: Order) -> None:
        ...


class EmailOrderNotifier:
    def __init__(
        self,
        smtp_host: str,
        sender_address: str,
        smtp_port: int = 25,
    ) -> None:
        self._smtp_host = smtp_host
        self._smtp_port = smtp_port
        self._sender = sender_address

    def notify_order_confirmed(self, order: Order) -> None:
        message = self._build_message(order)
        self._send(message, recipient=order.customer_email)

    def _build_message(self, order: Order) -> MIMEText:
        body = (
            f"Thank you! Your order #{order.id} has been confirmed.\n"
            f"Total charged: ${order.total:.2f}\n"
            f"Status: {order.status}"
        )
        msg = MIMEText(body)
        msg["Subject"] = f"Order Confirmation – #{order.id}"
        msg["From"] = self._sender
        msg["To"] = order.customer_email
        return msg

    def _send(self, message: MIMEText, recipient: str) -> None:
        try:
            with smtplib.SMTP(self._smtp_host, self._smtp_port) as server:
                server.send_message(message)
            logger.info("Confirmation email sent to %s", recipient)
        except smtplib.SMTPException as exc:
            # Log but don't crash the order – notification is a side-effect
            logger.error("Failed to send confirmation email: %s", exc)


class NullOrderNotifier:
    """No-op for tests or environments where email is disabled."""
    def notify_order_confirmed(self, order: Order) -> None:
        logger.debug("NullNotifier: skipping email for order %s", order.id)
