## `orchestrator.py` — Thin Coordinator (SRP)

```python
from typing import Any

from .validation import CompositeOrderValidator, build_default_validator
from .pricing import PricingCalculator, build_default_pricing_calculator
from .discounts import CouponRegistry, build_default_coupon_registry
from .order_factory import OrderFactory
from .notifications import OrderNotifier
from .models import Order


class OrderProcessingError(Exception):
    pass


class OrderOrchestrator:
    """
    Coordinates the pipeline. Contains zero business logic itself.

    Dependency Injection makes every collaborator swappable
    (e.g. swap EmailNotifier → NullNotifier in tests).
    """

    def __init__(
        self,
        validator: CompositeOrderValidator,
        pricing_calculator: PricingCalculator,
        coupon_registry: CouponRegistry,
        order_factory: OrderFactory,
        notifier: OrderNotifier,
    ) -> None:
        self._validator = validator
        self._pricing = pricing_calculator
        self._coupons = coupon_registry
        self._factory = order_factory
        self._notifier = notifier

    def process(self, order_data: dict[str, Any]) -> Order:
        # Step 1 – Validate
        result = self._validator.validate(order_data)
        if not result.is_valid:
            raise OrderProcessingError(result.error)

        # Step 2 – Resolve discount amount
        raw_items = order_data["items"]
        province = order_data.get("province")
        coupon_code = order_data.get("coupon_code")

        # Need a preliminary subtotal+tax+shipping to compute percentage discounts
        strategy = self._coupons.resolve(coupon_code)
        preliminary_pricing = self._pricing.calculate(raw_items, province, discount=0.0)
        discount_amount = strategy.apply(preliminary_pricing.total)

        # Step 3 – Final pricing with discount applied
        pricing = self._pricing.calculate(raw_items, province, discount=discount_amount)

        # Step 4 – Assemble order record
        order = self._factory.create(
            raw_items=raw_items,
            pricing=pricing,
            customer_email=order_data["customer_email"],
        )

        # Step 5 – Notify (non-blocking side-effect)
        self._notifier.notify_order_confirmed(order)

        return order


# ── Convenience factory ───────────────────────────────────────────────────────

def build_default_orchestrator(notifier: OrderNotifier) -> OrderOrchestrator:
    """Wire up the default production pipeline."""
    return OrderOrchestrator(
        validator=build_default_validator(),
        pricing_calculator=build_default_pricing_calculator(),
        coupon_registry=build_default_coupon_registry(),
        order_factory=OrderFactory(),
        notifier=notifier,
    )
```

