```typescript
// processData.ts
import { promises as fs } from 'fs';
import { ConfigError, NetworkError, ValidationError, VerificationError } from './errors';
import type { Config, ApiResponse, ApiItem, ProcessedItem, ProcessResult, RetryOptions } from './types';

// ─── Validation ──────────────────────────────────────────────────────────────

function validateConfig(raw: unknown): Config {
  if (!raw || typeof raw !== 'object') {
    throw new ValidationError('Config must be a non-null object');
  }

  const config = raw as Record<string, unknown>;

  if (typeof config.apiUrl !== 'string' || !config.apiUrl.trim()) {
    throw new ValidationError('Config missing valid "apiUrl"', 'apiUrl');
  }

  if (typeof config.outputPath !== 'string' || !config.outputPath.trim()) {
    throw new ValidationError('Config missing valid "outputPath"', 'outputPath');
  }

  try {
    new URL(config.apiUrl); // ensure it's a parseable URL
  } catch {
    throw new ValidationError(`"apiUrl" is not a valid URL: ${config.apiUrl}`, 'apiUrl');
  }

  return { apiUrl: config.apiUrl.trim(), outputPath: config.outputPath.trim() };
}

function validateApiResponse(raw: unknown): ApiResponse {
  if (!raw || typeof raw !== 'object') {
    throw new ValidationError('API response must be a non-null object');
  }

  const response = raw as Record<string, unknown>;

  if (!Array.isArray(response.items)) {
    throw new ValidationError('API response missing "items" array', 'items');
  }

  const items = response.items.map((item: unknown, index: number): ApiItem => {
    if (!item || typeof item !== 'object') {
      throw new ValidationError(`Item at index ${index} is not an object`);
    }

    const record = item as Record<string, unknown>;

    if (record.id === undefined || record.id === null) {
      throw new ValidationError(`Item at index ${index} missing "id"`, 'id');
    }

    if (typeof record.name !== 'string' || !record.name.trim()) {
      throw new ValidationError(`Item at index ${index} missing valid "name"`, 'name');
    }

    return { id: record.id as string | number, name: record.name };
  });

  return { items };
}

// ─── Config Loading ───────────────────────────────────────────────────────────

async function loadConfig(configPath: string): Promise<Config> {
  if (!configPath || typeof configPath !== 'string') {
    throw new ValidationError('configPath must be a non-empty string');
  }

  let raw: string;
  try {
    raw = await fs.readFile(configPath, 'utf8');
  } catch (err) {
    throw new ConfigError(
      `Failed to read config file at "${configPath}": ${(err as NodeJS.ErrnoException).message}`,
      err
    );
  }

  let parsed: unknown;
  try {
    parsed = JSON.parse(raw);
  } catch (err) {
    throw new ConfigError(
      `Config file at "${configPath}" contains invalid JSON`,
      err
    );
  }

  return validateConfig(parsed);
}

// ─── HTTP with Retry ─────────────────────────────────────────────────────────

const DEFAULT_RETRY_OPTIONS: RetryOptions = {
  maxAttempts: 3,
  delayMs: 500,
  backoffMultiplier: 2,
};

async function sleep(ms: number): Promise<void> {
  return new Promise(resolve => setTimeout(resolve, ms));
}

async function fetchWithRetry(
  url: string,
  options: Partial<RetryOptions> = {}
): Promise<ApiResponse> {
  const { maxAttempts, delayMs, backoffMultiplier } = {
    ...DEFAULT_RETRY_OPTIONS,
    ...options,
  };

  let lastError: unknown;
  let currentDelay = delayMs;

  for (let attempt = 1; attempt <= maxAttempts; attempt++) {
    try {
      const response = await fetch(url);

      // Non-retryable client errors (4xx except 429)
      if (response.status >= 400 && response.status < 500 && response.status !== 429) {
        throw new NetworkError(
          `HTTP ${response.status}: ${response.statusText} — not retrying client error`,
          response.status
        );
      }

      // Retryable server/rate-limit errors
      if (!response.ok) {
        throw new NetworkError(
          `HTTP ${response.status}: ${response.statusText}`,
          response.status
        );
      }

      let body: unknown;
      try {
        body = await response.json();
      } catch (err) {
        throw new NetworkError('API returned invalid JSON', response.status, err);
      }

      return validateApiResponse(body);

    } catch (err) {
      // Re-throw non-retryable errors immediately
      if (err instanceof NetworkError && err.statusCode && err.statusCode >= 400 && err.statusCode < 500 && err.statusCode !== 429) {
        throw err;
      }
      if (err instanceof ValidationError) {
        throw err;
      }

      lastError = err;

      if (attempt < maxAttempts) {
        console.warn(
          `Attempt ${attempt}/${maxAttempts} failed: ${(err as Error).message}. ` +
          `Retrying in ${currentDelay}ms...`
        );
        await sleep(currentDelay);
        currentDelay *= backoffMultiplier;
      }
    }
  }

  throw new NetworkError(
    `All ${maxAttempts} attempts failed. Last error: ${(lastError as Error).message}`,
    undefined,
    lastError
  );
}

// ─── Data Processing ──────────────────────────────────────────────────────────

function transformItems(items: ApiItem[]): ProcessedItem[] {
  return items.map(item => ({
    id: item.id,
    name: item.name.toUpperCase(),
    processed: true as const,
  }));
}

// ─── File Output & Verification ───────────────────────────────────────────────

async function writeAndVerify(
  outputPath: string,
  results: ProcessedItem[]
): Promise<void> {
  try {
    await fs.writeFile(outputPath, JSON.stringify(results, null, 2), 'utf8');
  } catch (err) {
    throw new ConfigError(
      `Failed to write output to "${outputPath}": ${(err as NodeJS.ErrnoException).message}`,
      err
    );
  }

  let written: string;
  try {
    written = await fs.readFile(outputPath, 'utf8');
  } catch (err) {
    throw new ConfigError(
      `Failed to read back output from "${outputPath}" for verification`,
      err
    );
  }

  let verified: unknown;
  try {
    verified = JSON.parse(written);
  } catch (err) {
    throw new ConfigError('Written file contains invalid JSON — write may be corrupted', err);
  }

  if (!Array.isArray(verified) || verified.length !== results.length) {
    throw new VerificationError(
      'Written file content does not match expected results',
      results.length,
      Array.isArray(verified) ? verified.length : -1
    );
  }
}

// ─── Public API ───────────────────────────────────────────────────────────────

export async function processData(
  configPath: string,
  retryOptions?: Partial<RetryOptions>
): Promise<ProcessResult> {
  const config = await loadConfig(configPath);
  const apiResponse = await fetchWithRetry(config.apiUrl, retryOptions);
  const results = transformItems(apiResponse.items);
  await writeAndVerify(config.outputPath, results);

  return { count: results.length, path: config.outputPath };
}
```

### Usage Example

```typescript
// main.ts
import { processData } from './processData';
import { ConfigError, NetworkError, ValidationError, VerificationError } from './errors';

async function main() {
  try {
    const result = await processData('./config.json', {
      maxAttempts: 3,
      delayMs: 1000,
      backoffMultiplier: 2,
    });

    console.log(`✅ Processed ${result.count} items → ${result.path}`);

  } catch (err) {
    // Handle each error type distinctly
    if (err instanceof ValidationError) {
      console.error(`❌ Validation failed${err.field ? ` [${err.field}]` : ''}: ${err.message}`);
      process.exit(1);
    } else if (err instanceof ConfigError) {
      console.error(`❌ Config/IO error: ${err.message}`);
      process.exit(1);
    } else if (err instanceof NetworkError) {
      console.error(`❌ Network error${err.statusCode ? ` (HTTP ${err.statusCode})` : ''}: ${err.message}`);
      process.exit(2);
    } else if (err instanceof VerificationError) {
      console.error(`❌ Verification failed: expected ${err.expected}, got ${err.actual}`);
      process.exit(3);
    } else {
      console.error('❌ Unexpected error:', err);
      process.exit(99);
    }
  }
}

main();
```

## Key Improvements

| Area | Before | After |
|---|---|---|
| **Control flow** | Nested callbacks | Linear `async/await` |
| **Error handling** | Single `callback(err)` | Typed custom error classes |
| **HTTP** | `https.get` + manual body buffering | `fetch` (native Node 18+) |
| **Retries** | None | Exponential backoff, non-retryable detection |
| **Validation** | None | Input + API response validation |
| **Types** | None | Full TypeScript coverage |
| **Separation** | Monolithic function | Single-responsibility helpers |

**Critical design decisions:**
- **Non-retryable errors** (4xx except 429) throw immediately — no point burning retry budget on auth/not-found errors
- **`VerificationError`** carries both expected/actual counts so callers can make informed decisions
- **`validateApiResponse`** catches bad API contracts early with precise field-level messages rather than a cryptic `Cannot read property 'toUpperCase' of undefined` downstream

## Typed TypeScript Implementation

```typescript
/**
 * Groups array elements by a key derived from each item.
 *
 * @param array - The array to group
 * @param keyFn - Function that returns a string or number key for each item
 * @returns An object mapping keys to arrays of matching items
 */
function groupBy<T>(
  array: T[],
  keyFn: (item: T) => string | number
): Record<string | number, T[]> {
  return array.reduce<Record<string | number, T[]>>((groups, item) => {
    const key = keyFn(item);
    if (!groups[key]) {
      groups[key] = [];
    }
    groups[key].push(item);
    return groups;
  }, {});
}

/**
 * Returns a new sorted array based on a key derived from each item.
 *
 * @param array - The array to sort
 * @param keyFn - Function that returns a comparable value for each item
 * @param descending - Sort in descending order if true (default: false)
 * @returns A new sorted array
 */
function sortBy<T, K extends string | number | boolean | Date>(
  array: T[],
  keyFn: (item: T) => K,
  descending: boolean = false
): T[] {
  return [...array].sort((a, b) => {
    const valA = keyFn(a);
    const valB = keyFn(b);
    const cmp = valA < valB ? -1 : valA > valB ? 1 : 0;
    return descending ? -cmp : cmp;
  });
}

// Overloaded signatures for pipe() with up to 5 composed functions.
// Each overload precisely tracks the input and output types through the chain.
function pipe<A, B>(fn1: (input: A) => B): (input: A) => B;
function pipe<A, B, C>(fn1: (input: A) => B, fn2: (input: B) => C): (input: A) => C;
function pipe<A, B, C, D>(fn1: (input: A) => B, fn2: (input: B) => C, fn3: (input: C) => D): (input: A) => D;
function pipe<A, B, C, D, E>(fn1: (input: A) => B, fn2: (input: B) => C, fn3: (input: C) => D, fn4: (input: D) => E): (input: A) => E;
function pipe<A, B, C, D, E, F>(fn1: (input: A) => B, fn2: (input: B) => C, fn3: (input: C) => D, fn4: (input: D) => E, fn5: (input: E) => F): (input: A) => F;
// Fallback overload for longer chains where precise typing isn't tracked
function pipe(...fns: Array<(input: unknown) => unknown>): (input: unknown) => unknown;

/**
 * Composes functions left-to-right, passing the output of each
 * as the input to the next.
 *
 * @param fns - Functions to compose in order
 * @returns A new function representing the full pipeline
 */
function pipe(...fns: Array<(input: unknown) => unknown>): (input: unknown) => unknown {
  return (input: unknown) => fns.reduce<unknown>((acc, fn) => fn(acc), input);
}
```

### Key Design Decisions

| Feature | Approach |
|---|---|
| `groupBy` key type | `string \| number` — mirrors valid JS object key types |
| `sortBy` key constraint | `K extends string \| number \| boolean \| Date` — covers all natively comparable primitives |
| `sortBy` return type | `T[]` — explicitly a new array, not `void` |
| `pipe` typing | Overloads for 1–5 functions with precise type tracking, plus a fallback |
| `pipe` fallback | Uses `unknown` instead of `any` to preserve type safety |

### Usage Example

```typescript
interface User {
  name: string;
  age: number;
  department: string;
}

const users: User[] = [
  { name: "Alice", age: 30, department: "Engineering" },
  { name: "Bob",   age: 25, department: "Design" },
  { name: "Carol", age: 35, department: "Engineering" },
];

// groupBy: infers Record<string | number, User[]>
const byDept = groupBy(users, (u) => u.department);

// sortBy: infers User[], K inferred as number
const sorted = sortBy(users, (u) => u.age, true);

// pipe: return type correctly inferred as User[]
const process = pipe(
  (arr: User[]) => sortBy(arr, (u) => u.age),
  (arr: User[]) => groupBy(arr, (u) => u.department)
);
const result = process(users);
```

