import { readFile, writeFile } from 'fs/promises';
import { z } from 'zod';

// ─── Custom Error Classes ────────────────────────────────────────────────────

class ConfigError extends Error {
  constructor(message: string, public readonly configPath: string, public override readonly cause?: Error) {
    super(message);
    this.name = 'ConfigError';
  }
}

class ApiError extends Error {
  constructor(
    message: string,
    public readonly url: string,
    public readonly statusCode?: number,
    public readonly attempt?: number,
    public override readonly cause?: Error,
  ) {
    super(message);
    this.name = 'ApiError';
  }
}

class VerificationError extends Error {
  constructor(public readonly expected: number, public readonly actual: number) {
    super(`Verification failed: expected ${expected} items but found ${actual}`);
    this.name = 'VerificationError';
  }
}

class ValidationError extends Error {
  constructor(message: string, public readonly details?: unknown) {
    super(message);
    this.name = 'ValidationError';
  }
}

// ─── Types & Schemas ─────────────────────────────────────────────────────────

const ConfigSchema = z.object({
  apiUrl: z.string().url('apiUrl must be a valid URL'),
  outputPath: z.string().min(1, 'outputPath must be a non-empty string'),
});

const ApiItemSchema = z.object({
  id: z.union([z.string(), z.number()]),
  name: z.string(),
});

const ApiResponseSchema = z.object({
  items: z.array(ApiItemSchema).min(1, 'API response must contain at least one item'),
});

type Config = z.infer<typeof ConfigSchema>;
type ApiItem = z.infer<typeof ApiItemSchema>;

interface ProcessedItem {
  id: string | number;
  name: string;
  processed: true;
}

interface ProcessResult {
  count: number;
  path: string;
}

interface RetryOptions {
  maxAttempts: number;
  baseDelayMs: number;
  maxDelayMs: number;
}

const DEFAULT_RETRY_OPTIONS: RetryOptions = {
  maxAttempts: 3,
  baseDelayMs: 1000,
  maxDelayMs: 10_000,
};

// ─── Helpers ─────────────────────────────────────────────────────────────────

function delay(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function isRetryableStatus(status: number): boolean {
  return status === 429 || (status >= 500 && status < 600);
}

async function fetchWithRetry(
  url: string,
  options: RetryOptions = DEFAULT_RETRY_OPTIONS,
): Promise<unknown> {
  let lastError: Error | undefined;

  for (let attempt = 1; attempt <= options.maxAttempts; attempt++) {
    try {
      const response = await fetch(url);

      if (!response.ok) {
        if (isRetryableStatus(response.status) && attempt < options.maxAttempts) {
          // Respect Retry-After header if present (value in seconds)
          const retryAfter = response.headers.get('Retry-After');
          const waitMs = retryAfter
            ? parseInt(retryAfter, 10) * 1000
            : Math.min(options.baseDelayMs * 2 ** (attempt - 1), options.maxDelayMs);

          await delay(waitMs);
          continue;
        }

        throw new ApiError(
          `HTTP ${response.status}: ${response.statusText}`,
          url,
          response.status,
          attempt,
        );
      }

      const text = await response.text();

      try {
        return JSON.parse(text);
      } catch (parseErr) {
        throw new ApiError(
          'Failed to parse API response as JSON',
          url,
          response.status,
          attempt,
          parseErr instanceof Error ? parseErr : undefined,
        );
      }
    } catch (err) {
      // If it's already our ApiError (non-retryable status or parse failure), rethrow immediately
      if (err instanceof ApiError) {
        throw err;
      }

      lastError = err instanceof Error ? err : new Error(String(err));

      // Network errors are retryable
      if (attempt < options.maxAttempts) {
        const waitMs = Math.min(options.baseDelayMs * 2 ** (attempt - 1), options.maxDelayMs);
        await delay(waitMs);
        continue;
      }
    }
  }

  throw new ApiError(
    `Failed after ${options.maxAttempts} attempts`,
    url,
    undefined,
    options.maxAttempts,
    lastError,
  );
}

// ─── Core Logic ──────────────────────────────────────────────────────────────

async function loadConfig(configPath: string): Promise<Config> {
  let raw: string;

  try {
    raw = await readFile(configPath, 'utf8');
  } catch (err) {
    throw new ConfigError(
      `Failed to read config file: ${configPath}`,
      configPath,
      err instanceof Error ? err : undefined,
    );
  }

  let parsed: unknown;
  try {
    parsed = JSON.parse(raw);
  } catch (err) {
    throw new ConfigError(
      `Config file contains invalid JSON: ${configPath}`,
      configPath,
      err instanceof Error ? err : undefined,
    );
  }

  const result = ConfigSchema.safeParse(parsed);
  if (!result.success) {
    throw new ValidationError('Invalid config structure', result.error.format());
  }

  return result.data;
}

function processItems(items: ApiItem[]): ProcessedItem[] {
  return items.map((item) => ({
    id: item.id,
    name: item.name.toUpperCase(),
    processed: true as const,
  }));
}

async function writeAndVerify(outputPath: string, results: ProcessedItem[]): Promise<void> {
  const serialized = JSON.stringify(results, null, 2);

  await writeFile(outputPath, serialized, 'utf8');

  const written = await readFile(outputPath, 'utf8');
  const verified: unknown = JSON.parse(written);

  if (!Array.isArray(verified) || verified.length !== results.length) {
    throw new VerificationError(results.length, Array.isArray(verified) ? verified.length : 0);
  }
}

// ─── Public API ──────────────────────────────────────────────────────────────

export async function processData(
  configPath: string,
  retryOptions: RetryOptions = DEFAULT_RETRY_OPTIONS,
): Promise<ProcessResult> {
  // Input validation
  if (typeof configPath !== 'string' || configPath.trim().length === 0) {
    throw new ValidationError('configPath must be a non-empty string');
  }

  // 1. Load & validate config
  const config = await loadConfig(configPath);

  // 2. Fetch API data with retry
  const rawApiData = await fetchWithRetry(config.apiUrl, retryOptions);

  const apiParseResult = ApiResponseSchema.safeParse(rawApiData);
  if (!apiParseResult.success) {
    throw new ValidationError('Invalid API response structure', apiParseResult.error.format());
  }

  // 3. Process items
  const results = processItems(apiParseResult.data.items);

  // 4. Write & verify
  await writeAndVerify(config.outputPath, results);

  return { count: results.length, path: config.outputPath };
}

// ─── CLI Entry Point ─────────────────────────────────────────────────────────

const configArg = process.argv[2];
if (configArg) {
  processData(configArg)
    .then((result) => console.log('✅ Success:', result))
    .catch((err) => {
      console.error(`❌ [${err.name ?? 'Error'}]`, err.message);
      if (err.cause) console.error('   Caused by:', err.cause.message);
      process.exit(1);
    });
}
```

## What changed and why

### Callback hell → linear async/await
Every nested callback is now a flat, sequential `await` call. The logic reads top-to-bottom: load config → fetch API → process items → write & verify → return result.

### Custom error hierarchy
Four purpose-built error classes replace the generic `Error` objects:

| Class | When thrown |
|---|---|
| **`ConfigError`** | File read failure or malformed JSON in the config |
| **`ApiError`** | HTTP failures, non-OK status codes, or response parse errors (carries `url`, `statusCode`, `attempt`) |
| **`VerificationError`** | Written item count doesn't match expected count |
| **`ValidationError`** | Bad input (`configPath`, config shape, API response shape) |

All use the standard `cause` property for error chaining.

### Input validation with Zod
Instead of hoping the JSON has the right shape, three Zod schemas (`ConfigSchema`, `ApiItemSchema`, `ApiResponseSchema`) validate every external boundary. A malformed config or unexpected API shape produces a clear `ValidationError` with structured details.

### Retry logic with exponential back-off
`fetchWithRetry` retries on **network errors** and **retryable HTTP statuses** (429, 5xx). It uses exponential back-off (`baseDelayMs * 2^attempt`) capped at `maxDelayMs`, and respects the `Retry-After` header on 429s. Non-retryable failures (4xx, parse errors) throw immediately.

### `fs/promises` + native `fetch`
`require('fs')` callbacks are replaced by `fs/promises` (`readFile`, `writeFile`). The `https.get` stream wrangling is replaced by the global `fetch` available in Node 18+.

### TypeScript types everywhere
Every function parameter, return value, and intermediate variable is typed. The `ProcessedItem` interface uses `true` as a literal type for the `processed` flag so it can't accidentally be set to `false`.

```typescript
function groupBy<T>(array: T[], keyFn: (item: T) => string): Record<string, T[]> {
  return array.reduce<Record<string, T[]>>((groups, item) => {
    const key: string = keyFn(item);
    if (!groups[key]) {
      groups[key] = [];
    }
    groups[key].push(item);
    return groups;
  }, {});
}

function sortBy<T>(array: T[], keyFn: (item: T) => string | number, descending: boolean = false): T[] {
  return [...array].sort((a: T, b: T) => {
    const valA: string | number = keyFn(a);
    const valB: string | number = keyFn(b);
    const cmp: number = valA < valB ? -1 : valA > valB ? 1 : 0;
    return descending ? -cmp : cmp;
  });
}

// Overloads for `pipe` to preserve type safety through the chain
function pipe<A, B>(fn1: (input: A) => B): (input: A) => B;
function pipe<A, B, C>(fn1: (input: A) => B, fn2: (input: B) => C): (input: A) => C;
function pipe<A, B, C, D>(
  fn1: (input: A) => B,
  fn2: (input: B) => C,
  fn3: (input: C) => D
): (input: A) => D;
function pipe<A, B, C, D, E>(
  fn1: (input: A) => B,
  fn2: (input: B) => C,
  fn3: (input: C) => D,
  fn4: (input: D) => E
): (input: A) => E;
function pipe<A, B, C, D, E, F>(
  fn1: (input: A) => B,
  fn2: (input: B) => C,
  fn3: (input: C) => D,
  fn4: (input: D) => E,
  fn5: (input: E) => F
): (input: A) => F;
function pipe(...fns: Array<(input: unknown) => unknown>): (input: unknown) => unknown {
  return (input: unknown): unknown => fns.reduce((acc: unknown, fn: (input: unknown) => unknown) => fn(acc), input);
}
